channels = get_channels()

prefix_matches = [channel for channel in channels if channel.startswith("External")]
if len(prefix_matches) == 0:
    prefix_matches = [channel for channel in channels if channel.lower().startswith("external")]

if len(prefix_matches) == 0:
    raise ValueError("No channel starts with External.")

