elif len(exact_matches) == 1:
    target_channel = exact_matches[0]
elif len(lower_exact_matches) == 1:
    target_channel = lower_exact_matches[0]
else:
    raise NotEnoughInformationError("Multiple channels start with External.")

users_in_channel = get_users_in_channel(target_channel)

if "Charlie" not in users_in_channel:
    add_user_to_channel("Charlie", target_channel)
